SELECT COUNT(id) from cd_indent WHERE 1 = 1

    AND  DATE_FORMAT(create_time,'%Y-%m') = #{time}


    AND  DATE_FORMAT(update_time,'%Y-%m') = #{time}

SELECT id,plate,username,brand_id brandId,phone,maint_plan maintPlan,car_ins carIns, busines_source businesSource, create_time createTime,work_time workTime,remark,state
FROM cd_indent WHERE 1 = 1
AND state = #{type}
AND (plate LIKE "%"#{text,jdbcType=VARCHAR}"%" or car_ins LIKE "%"#{text,jdbcType=VARCHAR}"%")
AND DATE_FORMAT(create_time,'%Y-%m') = #{time}
ORDER by create_time DESC LIMIT #{pagesize},20

SELECT id,plate,username,brand_id brandId,phone,maint_plan maintPlan,car_ins carIns, busines_source businesSource, create_time createTime,work_time workTime,remark,state
FROM cd_indent WHERE state BETWEEN 1 and 5
AND DATE_FORMAT(create_time,'%Y-%m') = #{time}

SELECT id,plate,username,brand_id brandId,phone,maint_plan maintPlan,car_ins carIns, busines_source businesSource, create_time createTime,work_time workTime,remark,state
FROM cd_indent WHERE 1 = 1
AND state = #{type}
AND (plate LIKE "%"#{text,jdbcType=VARCHAR}"%" or car_ins LIKE "%"#{text,jdbcType=VARCHAR}"%")
AND DATE_FORMAT(update_time,'%Y-%m') = #{time}
ORDER by create_time DESC LIMIT #{pagesize},20
